import java.util.InputMismatchException; import java.util.Random; import java.util.Scanner; public class BuggyProgram {     public static int[] generateNumbers(int count) {         Random rand = new Random();         int[] nums = new int[count];         for(int i = 0; i < count; i++) {             nums[i] = rand.nextInt(100);         }         return nums;     }     public static double average(int[] arr) {         int sum = 0;         for(int i = 0; i < arr.length; i++) {             sum += arr[i];         }         return (double) sum / arr.length;     }     public static int findMax(int[] arr) {         if(arr.length == 0) {             throw new RuntimeException("Array is empty");         }         int max = arr[0];         for(int i = 1; i < arr.length; i++) {             if(arr[i] > max) {                 max = arr[i];             }         }         return max;     }     public static int divide(int a, int b) {         if(b == 0) {             throw new ArithmeticException("Cannot divide by zero");         }         return a / b;     }     public static void main(String[] args) {         Scanner sc = new Scanner(System.in);         System.out.print("How many numbers: ");         int count;         try {             count = sc.nextInt();         } catch (InputMismatchException e) {             System.out.println("Invalid input");             return;         }         int[] numbers = generateNumbers(count);         System.out.println("Average: " + average(numbers));         System.out.println("Max: " + findMax(numbers));         for(int i = 0; i < numbers.length; i++) {             System.out.println(numbers[i]);         }         try {             System.out.println("Division test: " + divide(10, 0));         } catch (ArithmeticException e) {             System.out.println(e.getMessage());         }         if(count == 5) {             System.out.println("Count is 5");         }         sc.close();     } }